import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const Footer = () => {
  const { t } = useTranslation();
  const [deployTime, setDeployTime] = useState('');

  useEffect(() => {
    // Auto-updating timestamp
    const updateTime = () => {
      const now = new Date();
      setDeployTime(now.toLocaleString('fr-FR', {
        day: 'numeric',
        month: 'long',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        timeZone: 'Africa/Kinshasa'
      }));
    };

    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-grid">
          {/* Column 1: MAONI */}
          <div className="footer-column">
            <h4>MAONI</h4>
            <p style={{ marginBottom: '1rem', color: 'var(--gray-400)' }}>
              Plateforme nationale de consultation citoyenne pour la réforme constitutionnelle 
              en République Démocratique du Congo. La voix de 80 millions de Congolais.
            </p>
            <img 
              src="/images/logo-drc-map.png" 
              alt="DRC" 
              className="logo-footer"
            />
          </div>

          {/* Column 2: Entreprise */}
          <div className="footer-column">
            <h4>Entreprise</h4>
            <ul className="footer-links">
              <li><Link to="/" className="footer-link">Accueil</Link></li>
              <li><Link to="/proposals" className="footer-link">Propositions</Link></li>
              <li><Link to="/statistics" className="footer-link">Statistiques</Link></li>
              <li><Link to="/about" className="footer-link">À propos</Link></li>
              <li><Link to="/terms" className="footer-link">Conditions d'utilisation</Link></li>
              <li><Link to="/privacy" className="footer-link">Politique de confidentialité</Link></li>
            </ul>
          </div>

          {/* Column 3: Resources */}
          <div className="footer-column">
            <h4>Ressources</h4>
            <ul className="footer-links">
              <li>
                <a href="#" className="footer-link" target="_blank" rel="noopener noreferrer">
                  📘 Facebook
                </a>
              </li>
              <li>
                <a href="#" className="footer-link" target="_blank" rel="noopener noreferrer">
                  🐦 Twitter / X
                </a>
              </li>
              <li>
                <a href="#" className="footer-link" target="_blank" rel="noopener noreferrer">
                  📺 YouTube
                </a>
              </li>
              <li>
                <a href="#" className="footer-link" target="_blank" rel="noopener noreferrer">
                  💬 WhatsApp Channel
                </a>
              </li>
              <li>
                <a href="#" className="footer-link" target="_blank" rel="noopener noreferrer">
                  📱 Telegram
                </a>
              </li>
            </ul>
          </div>

          {/* Column 4: Contact */}
          <div className="footer-column">
            <h4>Contact</h4>
            <ul className="footer-links">
              <li className="footer-link">
                📍 Kinshasa, RDC
              </li>
              <li className="footer-link">
                📧 contact@maoni.cd
              </li>
              <li className="footer-link">
                📞 +243 800 000 000
              </li>
              <li className="footer-link">
                🏛️ Département Présidentiel
              </li>
            </ul>
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="footer-bottom">
          <p className="footer-deploy-time">
            Dernière mise à jour : {deployTime} (Heure de Kinshasa)
          </p>
          <p style={{ marginTop: '0.5rem' }}>
            <span className="footer-made-in">🇨🇩 Made in DRC</span> | 
            © {new Date().getFullYear()} MAONI - Tous droits réservés | 
            v100.04
          </p>
        </div>
      </div>
    </footer>
  );
};

export default Footer;